import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import { FormService, type FormDesign, RelationItemModel } from "@umbraco-forms/generated";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../form-workspace.context-token.js";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { DateTimeOptions } from "@umbraco-forms/entities";

const elementName = "workspace-view-form-info";

@customElement(elementName)
export class UmbWorkspaceViewFormInfoElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  @state()
  _form?: FormDesign;

  @state()
  _relations: Array<RelationItemModel> = [];

  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
      this.#workspaceContext = instance;
      this.#observeForm();
    });
  }

  #observeForm() {
    if (!this.#workspaceContext) return;

    this.observe(this.#workspaceContext.data, async (form) => {
      if (!form) return;
      this._form = form;

      if (!this.#workspaceContext?.getIsNew()) {
        await this.#populateRelations(form.id);
      }
    });
  }

  async #populateRelations(id: string) {
    const { data } = await tryExecuteAndNotify(
      this,
      FormService.getFormByIdRelations({
        id: id,
      })
    );

    if (data) {
      this._relations = data.items;
    }
  }

  render() {
    return html` <uui-box .headline=${this.localize.term("general_general")}>
        <umb-property-layout .label=${this.localize.term("general_id")}>
          <span slot="editor">${this._form?.unique}</span>
        </umb-property-layout>
        ${when(!this.#workspaceContext?.getIsNew(),
          () => html`
            <umb-property-layout .label=${this.localize.term("content_createDate")}>
              <umb-localize-date
                slot="editor"
                .date=${this._form?.created}
                .options=${DateTimeOptions}
              ></umb-localize-date>
            </umb-property-layout>
            ${when(this._form?.createdBy,
              () => html`
                <umb-property-layout .label=${this.localize.term("content_createBy")}>
                  <div slot="editor">${this._form?.createdByName}</div>
                </umb-property-layout>`)}
            <umb-property-layout .label=${this.localize.term("content_updateDate")}>
              <umb-localize-date
                slot="editor"
                .date=${this._form?.updated}
                .options=${DateTimeOptions}
              ></umb-localize-date>
            </umb-property-layout>
            ${when(this._form?.updatedBy,
              () => html`
                <umb-property-layout .label=${this.localize.term("content_updatedBy")}>
                  <div slot="editor">${this._form?.updatedByName}</div>
                </umb-property-layout>`)}
          `)}
      </uui-box>
      ${when(!this.#workspaceContext?.getIsNew(),
        () => html`
          <uui-box headline=${this.localize.term("formSettings_referencesTitle")}>
            <uui-table>
              <uui-table-head>
                <uui-table-head-cell
                  >${this.localize.term(
                    "general_nodeName"
                  )}</uui-table-head-cell
                >
                <uui-table-head-cell
                  >${this.localize.term(
                    "general_status"
                  )}</uui-table-head-cell
                >
                <uui-table-head-cell
                  >${this.localize.term(
                    "general_typeName"
                  )}</uui-table-head-cell
                >
                <uui-table-head-cell
                  >${this.localize.term(
                    "general_type"
                  )}</uui-table-head-cell
                >
                <uui-table-head-cell
                  >${this.localize.term(
                    "relationType_relation"
                  )}</uui-table-head-cell
                >
              </uui-table-head>
              ${this._relations.map(
                (relation) =>
                  html`<uui-table-row>
                    <uui-table-cell>${relation.nodeName}</uui-table-cell>
                    <uui-table-cell>${this.localize.term(
                      "content_" + (relation.nodePublished ? "published" : "unpublished")
                    )}</uui-table-cell>
                    <uui-table-cell>${relation.contentTypeName}</uui-table-cell>
                    <uui-table-cell>${relation.nodeType}</uui-table-cell>
                    <uui-table-cell>${relation.relationTypeName}</uui-table-cell>
                  </uui-table-row>`
              )}
            </uui-table>
          </uui-box>`)}
      `;
  }

  static styles = [
    css`
      :host {
        display: block;
        padding: var(--uui-size-layout-1);
      }

      uui-box + uui-box {
        margin-top: var(--uui-size-layout-1);
      }
    `,
  ];
}

export default UmbWorkspaceViewFormInfoElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewFormInfoElement;
  }
}
